<?php
require_once __DIR__ . '/bootstrap.php';
$method = request_method(); $data = request_data();
if ($method === 'GET') { $status = query('status', 'Published'); respond(['success' => true, 'items' => db_all('SELECT * FROM testimonials WHERE (? = "all" OR status = ?) ORDER BY id DESC', [$status, $status])]); }
if ($method === 'POST' && empty($data['admin_update'])) { $id = db_insert('INSERT INTO testimonials (customer_name, customer_role, rating, testimonial_text, image_url, status) VALUES (?, ?, ?, ?, ?, ?)', [trim((string)$data['customer_name']), trim((string)($data['customer_role'] ?? '')), max(1, min(5, (int)($data['rating'] ?? 5))), trim((string)$data['testimonial_text']), trim((string)($data['image_url'] ?? '')), 'Pending']); respond(['success' => true, 'id' => $id]); }
require_admin(); $id = (int)($data['id'] ?? query('id', 0)); if ($method === 'PUT' || $method === 'POST') { db_exec('UPDATE testimonials SET customer_name=?, customer_role=?, rating=?, testimonial_text=?, image_url=?, status=? WHERE id=?', [trim((string)$data['customer_name']), trim((string)($data['customer_role'] ?? '')), max(1, min(5, (int)($data['rating'] ?? 5))), trim((string)$data['testimonial_text']), trim((string)($data['image_url'] ?? '')), trim((string)($data['status'] ?? 'Published')), $id]); respond(['success' => true]); } db_exec('DELETE FROM testimonials WHERE id=?', [$id]); respond(['success' => true]);
